//класс Треугольник
Triangle::Triangle(Figure::Point p1, Figure::Point p2, Figure::Point p3, int color):
	Figure(color), p1(p2), p2(p2), p3(p3) {}

double Triangle::place() const {
#ifdef DEBUG
	std::cerr << "In Triangle::place()\n";
#endif 
	double ans = 0.5 * ((p1.x - p3.x) * (p2.y - p3.y) - (p2.x - p3.x) * (p1.y - p3.y));
	if (ans < 0) ans = -ans;
	return ans;
}

double Triangle::perimetr() const {
#ifdef DEBUG
	std::cerr << "In Triangle::perimetr()\n";
#endif 
	double dist1 = std::sqrt(std::pow(p1.x - p2.x, 2) +std::pow(p1.y - p2.y, 2)); //рсстояние двух точек на плоскости
	double dist2 = std::sqrt(std::pow(p2.x - p3.x, 2) + std::pow(p2.y - p3.y, 2));
	double dist3 = std::sqrt(std::pow(p3.x - p1.x, 2) + std::pow(p3.y - p1.y, 2));
	return dist1 + dist2 + dist3;
}

Figure::Point Triangle::getP1() const { return p1; }
Figure::Point Triangle::getP2() const { return p2; }
Figure::Point Triangle::getP3() const { return p3; }

