//класс Полигон
Polygon::Polygon(vector<Point> points, int numPoints, int color) : 
	Figure(color), points(points), numPoints(numPoints) {}

double Polygon::place() const {
#ifdef DEBUG
	std::cerr << "In Polygon::place()\n";
#endif 
	double area = 0.0;
	int n = points.size();
	for (int i = 0; i < n; i++)
	{
		int j = (i + 1) % n;
		area += (points[i].x + points[j].x) * (points[i].y - points[j].y);
	}
	area /= 2.0;
	return std::abs(area);
}

double Polygon::perimetr() const {
#ifdef DEBUG
	std::cerr << "In Polygon::perimetr()\n";
#endif 
	double perimeter = 0.0;
	for (int i = 0; i < numPoints; i++)
	{
		int j = (i + 1) % numPoints;
		double dist = std::sqrt(std::pow(points[i].x - points[j].x, 2) + std::pow(points[i].y - points[j].y, 2));
		perimeter += dist;
	}
	return perimeter;
}

vector<Figure::Point> Polygon::getPoints() const
{
	return points;
}

int Polygon::getSize() const
{
	return numPoints;
}

void Polygon::Print(std::ostream& stream) const
{
	stream << "Size = " << getSize();
}

void Polygon::readinFile(std::ostream& stream)
{
	stream << "Size = " << getSize();
}
std::string Polygon::writeinFile(std::ifstream& stream)
{
	std::string line;
	while (stream >> line) { // Считывает данные из файла построчно
		std::cout << line << std::endl; // Выводит считанные данные в консоль
	}
	return line;
}

