bool FiguresFactory::RegisterFigure(const std::string& figureType, CreateFigureCallback CreateFN) {
    return callbacks.insert(CallbackMap::value_type(figureType, CreateFN)).second;
}

bool FiguresFactory::UnregisterFigure(const std::string& figureType) {
    return callbacks.erase(figureType) == 1;
}

Figure* FiguresFactory::CreateFigure(const std::string& figureType, std::istream& stream) {
