#pragma once
#include "singleton.h"
#include "Figure.h"
#include <string>
#include <map>
#include <memory>
#include <istream>
#include <functional>

class FiguresFactory : public Singleton<FiguresFactory> {
public:
    // Функция-обратного вызова для создания фигуры из потока;
    // отличается от CreateFigureCallback тем, что принимает источник данных
    typedef std::function<Figure*(std::istream&)> CreateFigureFromFileCallback;

private:
    // Карта использует имя фигуры как ключ и функцию для создания фигур из потока в качестве значения
    std::map<std::string, CreateFigureFromFileCallback> callbacks;

public:
    // Регистрация типа фигуры с указанной функцией обратного вызова
    bool RegisterFigure(const std::string& figureName, CreateFigureFromFileCallback callback) {
        return callbacks.insert(std::make_pair(figureName, callback)).second;
    }

    // Удаляет зарегистрированную фигуру
    bool UnregisterFigure(const std::string& figureName) {
        return callbacks.erase(figureName) == 1;
    }

    // Создает фигуру, используя функцию обратного вызова, основанную на имени фигуры
    Figure* CreateFigureFromFile(std::istream& stream) {
        std::string figureName;
        stream >> figureName;
        auto it = callbacks.find(figureName);
        if (it == callbacks.end()) {
            throw std::runtime_error("Unknown figure name: " + figureName);
        }
        return it->second(stream);
    }
};

